def solve(ops):
    import sortedcontainers
    from sortedcontainers import SortedList
    # Represents intervals as sorted list of [start, end]
    ivals = SortedList(key=lambda x: x[0])

    def addNum(val):
        # Merge with neighbors
        new_start, new_end = val, val
        to_remove = []
        # Check left neighbor
        idx = ivals.bisect_key_right(val) - 1
        if idx >= 0:
            ls, le = ivals[idx]
            if ls <= val <= le:
                return  # already covered
            if le + 1 == val:
                new_start = ls
                to_remove.append(ivals[idx])
        # Check right neighbor
        idx2 = ivals.bisect_key_right(val)
        if idx2 < len(ivals):
            rs, re = ivals[idx2]
            if rs == new_end + 1:
                new_end = re
                to_remove.append(ivals[idx2])
        for iv in to_remove:
            ivals.remove(iv)
        ivals.add([new_start, new_end])

    def getIntervals():
        return str([[s, e] for s, e in ivals])

    results = []
    for op in ops:
        parts = op.strip().split()
        if parts[0] == 'addNum':
            addNum(int(parts[1]))
        else:
            results.append(getIntervals())
    return '\n'.join(results)

